class Solution {
public:
    bool canChange(string start, string target) {
        int n = start.size();
        int left_L = 0, right_L = 0, left_R = 0, right_R = 0;

        for (int i = 0; i < n; ++i) {
            if (start[i] == 'L') {
                left_L = i;
            } else if (start[i] == 'R') {
                right_R = i;
            }
            if (target[i] == 'L') {
                right_L = i;
            } else if (target[i] == 'R') {
                left_R = i;
            }
        }

        return left_L <= right_L && left_R >= right_R;
    }
};
